import React, { useState } from 'react';
import { FaRobot, FaPaperclip, FaDownload } from 'react-icons/fa';
import './Quadra.css';

const Quadra = ({ onClose }) => {
  const [messages, setMessages] = useState([
    {
      id: 1,
      text: "Hello! I'm Quadra, your AI assistant. How can I help you today?",
      isBot: true,
      timestamp: new Date(),
      type: 'text'
    }
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isThinking, setIsThinking] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);

  const handleSendMessage = async () => {
    if (!inputValue.trim()) return;

    const userMessage = {
      id: Date.now(),
      text: inputValue,
      isBot: false,
      timestamp: new Date(),
      type: 'text'
    };

    setMessages(prev => [...prev, userMessage]);
    setInputValue('');

    // Check for the exact trigger prompt
    if (inputValue === "Create a project Agentic AI Platform with quadrant email id as sahil.d@quadranttechnologies.com , dhanshika.v@quadranttechnologies.com CSA as abc@microsft.com and client with xyz@email.com and qwerty@email.com (POC)") {
      setIsThinking(true);
      setIsProcessing(true);

      // Simulate thinking process for 10 seconds
      setTimeout(() => {
        setIsThinking(false);

        // Send SOW file and approval request
        const sowMessage = {
          id: Date.now() + 1,
          text: "Please review and approve this SOW.",
          isBot: true,
          timestamp: new Date(),
          type: 'text'
        };

        const fileMessage = {
          id: Date.now() + 2,
          text: "SOW_Agentic_AI_Platform.pdf",
          isBot: true,
          timestamp: new Date(),
          type: 'file',
          fileName: "SOW_Agentic_AI_Platform.pdf",
          fileSize: "2.4 MB"
        };

        setMessages(prev => [...prev, sowMessage, fileMessage]);
        setIsProcessing(false);
      }, 10000);
    } else if (inputValue === "I approve") {
      // Handle approval
      const approvalMessage = {
        id: Date.now(),
        text: "The SOW has been sent to the POC email provided above.",
        isBot: true,
        timestamp: new Date(),
        type: 'text'
      };

      setMessages(prev => [...prev, approvalMessage]);
    } else {
      // Default response for other messages
      const defaultResponse = {
        id: Date.now(),
        text: "I'm here to help with project creation and SOW management. Please use the specific format to create a project.",
        isBot: true,
        timestamp: new Date(),
        type: 'text'
      };

      setMessages(prev => [...prev, defaultResponse]);
    }
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const downloadSOW = () => {
    // Create a sample SOW content (in real implementation, this would be the actual SOW file)
    const sowContent = `Statement of Work (SOW)

Project: Agentic AI Platform
Client: Confidential
Date: ${new Date().toLocaleDateString()}

1. PROJECT OVERVIEW
   - Project Name: Agentic AI Platform
   - Quadrant Team: sahil.d@quadranttechnologies.com, dhanshika.v@quadranttechnologies.com
   - CSA: abc@microsft.com
   - Client: xyz@email.com, qwerty@email.com
   - Type: POC

2. SCOPE OF WORK
   - AI Platform Development
   - Integration Services
   - Testing and Validation
   - Documentation

3. DELIVERABLES
   - Working AI Platform
   - Technical Documentation
   - User Manual
   - Test Results

4. TIMELINE
   - Start Date: TBD
   - End Date: TBD
   - Duration: TBD

5. TERMS AND CONDITIONS
   - This SOW is subject to client approval
   - All deliverables are confidential
   - Payment terms as per agreement`;

    const blob = new Blob([sowContent], { type: 'text/plain' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'SOW_Agentic_AI_Platform.txt';
    document.body.appendChild(a);
    a.click();
    window.URL.revokeObjectURL(url);
    document.body.removeChild(a);
  };

  return (
    <div className="quadra-container">
      <div className="quadra-header">
        <div className="quadra-title">
          <FaRobot className="quadra-icon" />
          <span>Quadra</span>
        </div>
        <button className="quadra-close" onClick={onClose}>
          ×
        </button>
      </div>

      <div className="quadra-messages">
        {messages.map((message) => (
          <div key={message.id} className={`quadra-message ${message.isBot ? 'bot' : 'user'}`}>
            {message.isBot && (
              <div className="quadra-avatar">
                <FaRobot />
              </div>
            )}
            <div className="quadra-message-content">
              {message.type === 'file' ? (
                <div className="quadra-file-message">
                  <div className="quadra-file-info">
                    <FaPaperclip className="file-icon" />
                    <span className="file-name">{message.fileName}</span>
                    <span className="file-size">{message.fileSize}</span>
                  </div>
                  <button className="quadra-download-btn" onClick={downloadSOW}>
                    <FaDownload /> Download SOW
                  </button>
                </div>
              ) : (
                <div className="quadra-text">{message.text}</div>
              )}
              <div className="quadra-timestamp">
                {message.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </div>
            </div>
          </div>
        ))}

        {isThinking && (
          <div className="quadra-message bot">
            <div className="quadra-avatar">
              <FaRobot />
            </div>
            <div className="quadra-message-content">
              <div className="quadra-thinking">
                <span className="thinking-text">Quadra is processing...</span>
                <div className="thinking-dots">
                  <span></span>
                  <span></span>
                  <span></span>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="quadra-input-container">
        <textarea
          className="quadra-input"
          value={inputValue}
          onChange={(e) => setInputValue(e.target.value)}
          onKeyPress={handleKeyPress}
          placeholder="Type your message here..."
          disabled={isProcessing}
        />
        <button 
          className="quadra-send-btn"
          onClick={handleSendMessage}
          disabled={!inputValue.trim() || isProcessing}
        >
          Send
        </button>
      </div>
    </div>
  );
};

export default Quadra;
